    # ---------------------------------------------------------------------------
    # Multi-message file splitter
    # ---------------------------------------------------------------------------


    def _split_messages(text: str) -> list[str]:
        """Split an HL7 batch file into individual message strings.

        Each message starts with an MSH line.  FHS/BHS/BTS/FTS batch-envelope
        segments are skipped.
        """
        normalised = text.strip().replace("\r\n", "\r").replace("\n", "\r")
        lines = normalised.split("\r")

        messages: list[str] = []
        current: list[str] = []
        _ENVELOPE = {"FHS", "BHS", "BTS", "FTS"}

        for line in lines:
            if not line.strip():
                continue
            seg_type = line[:3].upper()
            if seg_type in _ENVELOPE:
                continue
            if seg_type == "MSH":
                if current:
                    messages.append("\r".join(current))
                current = [line]
            else:
                current.append(line)

        if current:
            messages.append("\r".join(current))

        return messages


    # ---------------------------------------------------------------------------
    # Connector
    # ---------------------------------------------------------------------------


    class HL7LakeflowConnect(LakeflowConnect):
        """LakeflowConnect implementation for HL7 v2 message files.

        Reads ``.hl7`` (or other pattern) files from a Unity Catalog Volume path.
        Each HL7 segment type is a separate table.  Incremental loading is driven
        by file modification timestamps.

        Required options:
            volume_path (str): Path to the directory containing .hl7 files,
                e.g. ``/Volumes/catalog/schema/vol/hl7_feed/``.

        Optional options:
            file_pattern (str): Glob pattern for file matching (default ``*.hl7``).
                Use ``**/*.hl7`` for recursive search.
            max_records_per_batch (str): Max records per micro-batch (default 10000).
        """

        def __init__(self, options: dict[str, str]) -> None:
            super().__init__(options)
            if "volume_path" not in options:
                raise ValueError("'volume_path' is required in connector options.")
            self._volume_path = Path(options["volume_path"])
            self._file_pattern = options.get("file_pattern", _DEFAULT_FILE_PATTERN)
            self._max_records = int(options.get("max_records_per_batch", str(_DEFAULT_MAX_RECORDS)))

        # ------------------------------------------------------------------
        # LakeflowConnect interface
        # ------------------------------------------------------------------

        def list_tables(self) -> list[str]:
            return list(SEGMENT_TABLES)

        def get_table_schema(self, table_name: str, table_options: dict[str, str]) -> StructType:
            self._validate_table(table_name, table_options)
            segment_type = table_options.get("segment_type", table_name)
            return get_schema(segment_type)

        def read_table_metadata(self, table_name: str, table_options: dict[str, str]) -> dict:
            self._validate_table(table_name, table_options)
            segment_type = table_options.get("segment_type", table_name)
            return {"ingestion_type": "append", "description": TABLE_DESCRIPTIONS.get(segment_type, "")}

        def read_table(
            self, table_name: str, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            self._validate_table(table_name, table_options)
            segment_type = table_options.get("segment_type", table_name).upper()
            max_records = int(table_options.get("max_records_per_batch", str(self._max_records)))

            # Determine cursor: epoch-seconds float stored as string in offset dict.
            cursor: float | None = None
            if start_offset and "cursor" in start_offset:
                try:
                    cursor = float(start_offset["cursor"])
                except (ValueError, TypeError):
                    cursor = None

            files = self._list_files(cursor)
            if not files:
                return iter([]), start_offset or {"cursor": "0"}

            records: list[dict] = []
            max_mtime: float = cursor or 0.0

            for file_path, mtime in files:
                if len(records) >= max_records:
                    break
                max_mtime = max(max_mtime, mtime)
                try:
                    new_records = self._read_file(file_path, segment_type)
                    records.extend(new_records)
                except Exception as exc:  # pylint: disable=broad-except
                    warnings.warn(f"Skipping {file_path}: {exc}")

            if not records:
                return iter([]), {"cursor": str(max_mtime)}

            end_offset = {"cursor": str(max_mtime)}
            if start_offset and start_offset == end_offset:
                return iter([]), start_offset

            return iter(records), end_offset

        # ------------------------------------------------------------------
        # Private helpers
        # ------------------------------------------------------------------

        def _validate_table(self, table_name: str, table_options: dict) -> None:
            if table_name not in SEGMENT_TABLES and "segment_type" not in table_options:
                raise ValueError(
                    f"Unknown table '{table_name}'. "
                    f"Supported tables: {SEGMENT_TABLES}. "
                    "For custom/Z-segments, provide 'segment_type' in table_options."
                )

        def _list_files(self, after_mtime: float | None) -> list[tuple[Path, float]]:
            """Return (path, mtime) pairs sorted ascending by mtime.

            Only files with mtime *strictly after* ``after_mtime`` are returned.
            When ``after_mtime`` is None, all matching files are returned.
            """
            try:
                matched = list(self._volume_path.glob(self._file_pattern))
            except (OSError, ValueError) as exc:
                warnings.warn(f"Cannot list files at {self._volume_path}: {exc}")
                return []

            result: list[tuple[Path, float]] = []
            for p in matched:
                if not p.is_file():
                    continue
                try:
                    mtime = p.stat().st_mtime
                except OSError:
                    continue
                if after_mtime is None or mtime > after_mtime:
                    result.append((p, mtime))

            result.sort(key=lambda x: x[1])
            return result

        def _read_file(self, file_path: Path, segment_type: str) -> list[dict]:
            """Parse one HL7 file and return records for *segment_type*."""
            text = file_path.read_text(encoding="utf-8", errors="replace")
            source_file = file_path.name
            records: list[dict] = []

            for msg_text in _split_messages(text):
                msg: HL7Message | None = parse_message(msg_text)
                if msg is None:
                    continue
                msh = msg.get_segment("MSH")
                meta = _metadata(msh, source_file)

                if segment_type == "MSH":
                    if msh is not None:
                        records.append(meta | _extract_msh(msh))
                else:
                    extractor = _EXTRACTORS.get(segment_type.lower(), _extract_generic)
                    for seg in msg.get_segments(segment_type):
                        records.append(meta | extractor(seg))

            return records


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/lakeflow_datasource.py
    ########################################################

    LakeflowConnectImpl = HL7LakeflowConnect
    # Constant option or column names
    METADATA_TABLE = "_lakeflow_metadata"
    TABLE_NAME = "tableName"
    TABLE_NAME_LIST = "tableNameList"
    TABLE_CONFIGS = "tableConfigs"
    IS_DELETE_FLOW = "isDeleteFlow"


    class LakeflowStreamReader(SimpleDataSourceStreamReader):
        """
        Implements a data source stream reader for Lakeflow Connect.
        Currently, only the simpleStreamReader is implemented, which uses a
        more generic protocol suitable for most data sources that support
        incremental loading.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.lakeflow_connect = lakeflow_connect
            self.schema = schema

        def initialOffset(self):
            return {}

        def read(self, start: dict) -> (Iterator[tuple], dict):
            is_delete_flow = self.options.get(IS_DELETE_FLOW) == "true"
            # Strip delete flow options before passing to connector
            table_options = {
                k: v for k, v in self.options.items() if k != IS_DELETE_FLOW
            }

            if is_delete_flow:
                records, offset = self.lakeflow_connect.read_table_deletes(
                    self.options[TABLE_NAME], start, table_options
                )
            else:
                records, offset = self.lakeflow_connect.read_table(
                    self.options[TABLE_NAME], start, table_options
                )
            rows = map(lambda x: parse_value(x, self.schema), records)
            return rows, offset

        def readBetweenOffsets(self, start: dict, end: dict) -> Iterator[tuple]:
            # TODO: This does not ensure the records returned are identical across repeated calls.
            # For append-only tables, the data source must guarantee that reading from the same
            # start offset will always yield the same set of records.
            # For tables ingested as incremental CDC, it is only necessary that no new changes
            # are missed in the returned records.
            return self.read(start)[0]


    class LakeflowPartitionedStreamReader(DataSourceStreamReader):
        """Proxy that bridges SupportsPartitionedStream to PySpark's DataSourceStreamReader.

        Used when a connector implements the SupportsPartitionedStream mixin to
        support partitioned streaming reads across Spark executors.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self.table_options = {k: v for k, v in options.items() if k != IS_DELETE_FLOW}

        def initialOffset(self):
            return {}

        def latestOffset(self):
            # PySpark does not pass the current offset to latestOffset() yet,
            # so we forward None.  Once PySpark supports it, pass the real value.
            return self.lakeflow_connect.latest_offset(self.table_name, self.table_options, None)

        def partitions(self, start: dict, end: dict):
            partition_descs = self.lakeflow_connect.get_partitions(
                self.table_name, self.table_options, start, end
            )
            return [InputPartition(json.dumps(p)) for p in partition_descs]

        def read(self, partition: InputPartition):
            partition_desc = json.loads(partition.value)
            records = self.lakeflow_connect.read_partition(
                self.table_name, partition_desc, self.table_options
            )
            return map(lambda x: parse_value(x, self.schema), records)


    class LakeflowBatchReader(DataSourceReader):
        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self._supports_partition = isinstance(lakeflow_connect, SupportsPartition)

        def partitions(self):
            if self._supports_partition and self.table_name != METADATA_TABLE:
                try:
                    partition_descs = self.lakeflow_connect.get_partitions(
                        self.table_name, self.options
                    )
                    return [InputPartition(json.dumps(p)) for p in partition_descs]
                except Exception:
                    self._supports_partition = False
            return [InputPartition(None)]

        def read(self, partition):
            if self.table_name == METADATA_TABLE:
                records = self._read_table_metadata()
            elif self._supports_partition and partition.value is not None:
                partition_desc = json.loads(partition.value)
                records = self.lakeflow_connect.read_partition(
                    self.table_name, partition_desc, self.options
                )
            else:
                records, _ = self.lakeflow_connect.read_table(self.table_name, None, self.options)
            return map(lambda x: parse_value(x, self.schema), records)

        def _read_table_metadata(self):
            table_name_list = self.options.get(TABLE_NAME_LIST, "")
            table_names = [o.strip() for o in table_name_list.split(",") if o.strip()]
            all_records = []
            table_configs = json.loads(self.options.get(TABLE_CONFIGS, "{}"))
            for table in table_names:
                metadata = self.lakeflow_connect.read_table_metadata(
                    table, table_configs.get(table, {})
                )
                all_records.append({TABLE_NAME: table, **metadata})
            return all_records


    class LakeflowSource(DataSource):
        """
        PySpark DataSource implementation for Lakeflow Connect.
        """

        def __init__(self, options):
            self.options = options
            # TEMPORARY: LakeflowConnectImpl is replaced with the actual implementation
            # class during merge. See the placeholder comment at the top of this file.
            self.lakeflow_connect = LakeflowConnectImpl(options)  # pylint: disable=abstract-class-instantiated

        @classmethod
        def name(cls):
            return "lakeflow_connect"

        def schema(self):
            table = self.options[TABLE_NAME]
            if table == METADATA_TABLE:
                return StructType(
                    [
                        StructField(TABLE_NAME, StringType(), False),
                        StructField("primary_keys", ArrayType(StringType()), True),
                        StructField("cursor_field", StringType(), True),
                        StructField("ingestion_type", StringType(), True),
                    ]
                )
            else:
                return self.lakeflow_connect.get_table_schema(table, self.options)

        def reader(self, schema: StructType):
            return LakeflowBatchReader(self.options, schema, self.lakeflow_connect)

        def streamReader(self, schema: StructType):
            # Use the partitioned DataSourceStreamReader when the connector
            # implements SupportsPartitionedStream and the table opts in.
            # Otherwise, delegate to super() which raises PySparkNotImplementedError,
            # causing Spark to fall back to simpleStreamReader().
            if isinstance(self.lakeflow_connect, SupportsPartitionedStream):
                table = self.options[TABLE_NAME]
                if self.lakeflow_connect.is_partitioned(table):
                    return LakeflowPartitionedStreamReader(self.options, schema, self.lakeflow_connect)
            return super().streamReader(schema)

        def simpleStreamReader(self, schema: StructType):
            return LakeflowStreamReader(self.options, schema, self.lakeflow_connect)


    spark.dataSource.register(LakeflowSource)
